const PROCESSING_FEE = 5;
const FIRST_INSURANCE_MULTIPLIER = 1.1;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const itemPremium = (item: Item): number =>
  Math.ceil(BASE_PREMIUM_BY_TYPE[item.type] * FIRST_INSURANCE_MULTIPLIER);

const quoteStep = (step: QuoteStep) => {
  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
  return { premium: itemsTotal + PROCESSING_FEE };
};

export const processScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map(quoteStep);
  return { results };
};

